  const prog=PROGRAMS.find(p=>p.id===pid);
  const totalQ=prog.quizThemes.reduce((a,t)=>a+t.bank.length,0);

  const switchProg=(id)=>{setPid(id);setSec("referentiel");setSearch("");setAF(null);setAQT(null);setQM(null);setQS(null)};
